from collections import defaultdict
def detect_loops(crew_execution):
    delegation_graph = defaultdict(list)
    for step in crew_execution.steps:
        if step.delegate_to:
            delegation_graph[step.agent_id].append(step.delegate_to)

    visited = set()
    def has_cycle(node):
        if node in visited:
            return False
        visited.add(node)
        for neighbor in delegation_graph[node]:
            if neighbor in visited or has_cycle(neighbor):
                return True
        visited.remove(node)
        return False

    for agent_id in delegation_graph:
        if has_cycle(agent_id):
            return {'issue': 'DELEGATION_LOOP', 'agent': agent_id}
    return None

import re
def detect_hallucinated_tools(task_output):
    tool_calls = task_output.get('tools_used', [])
    hallucinations = []

    for tool_call in tool_calls:
        output = tool_call.get('output', '')
        # Common hallucination patterns
        if len(output) < 10 and tool_call['tool_name'] != 'search':
            hallucinations.append({
                'tool': tool_call['tool_name'],
                'reason': 'Output too short for tool'
            })
        elif re.search(r'\b(error|failed|not found)\b', output, re.IGNORECASE):
            hallucinations.append({
                'tool': tool_call['tool_name'],
                'reason': 'Tool reported failure but was passed downstream'
            })
    return {'issue': 'HALLUCINATED_TOOLS', 'count': len(hallucinations)} if hallucinations else None

