from crewai import Agent, Task

class LoopProtectedAgent(Agent):
    def __init__(self, *args, max_delegations=3, **kwargs):
        super().__init__(*args, **kwargs)
        self.delegation_count = 0
        self.max_delegations = max_delegations

    def should_delegate(self, task):
        if self.delegation_count >= self.max_delegations:
            return False, "Max delegation limit reached"
        self.delegation_count += 1
        return super().should_delegate(task)

# Usage
researcher = LoopProtectedAgent(
    role='Researcher',
    goal='Research topics',
    backstory='Expert researcher',
    max_delegations=2
)

task = Task(
    description='Research AI testing',
    agent=researcher
)

from crewai import Task

def validate_tool_output(tool_name, output):
    validators = {
        'search': lambda x: len(x) > 20 and 'result' in x.lower(),
        'calculator': lambda x: x.replace('.', '').isdigit(),
        'file_read': lambda x: len(x) > 0
    }
    return validators.get(tool_name, lambda x: True)(output)

class ValidatedTask(Task):
    def execute(self):
        result = super().execute()
        if hasattr(result, 'tools_used'):
            valid_tools = []
            for tool in result.tools_used:
                if validate_tool_output(tool['tool_name'], tool['output']):
                    valid_tools.append(tool)
                else:
                    print(f"⚠️ Invalid tool output: {tool['tool_name']}")
                    tool['output'] = "[VALIDATION FAILED]"
            result.tools_used = valid_tools
        return result

# Usage
validated_task = ValidatedTask(
    description="Use tools safely",
    expected_output="Validated results"
)
